using System;
using System.Collections.Generic;
using System.Linq;

class Student
{
    public string Name;
    public int Grade;

    public Student(string name, int grade)
    {
        Name = name;
        Grade = grade;
    }
}

class Program
{
    static void Main()
    {
        List<Student> students = new List<Student>
        {
            new Student("Ahmet", 85),
            new Student("Ayse", 92),
            new Student("Mehmet", 67),
            new Student("Zeynep", 78),
            new Student("Can", 55)
        };

        Console.WriteLine("Tum ogrenciler:");
        foreach (var s in students)
        {
            Console.WriteLine($"{s.Name}: {s.Grade}");
        }

        // Yeni ogrenci ekleme
        students.Add(new Student("Elif", 88));
        Console.WriteLine($"\nElif eklendi. Toplam ogrenci: {students.Count}");

        // Not güncelleme
        var student = students.First(s => s.Name == "Mehmet");
        student.Grade = 70;
        Console.WriteLine($"\nMehmet'in notu guncellendi: {student.Grade}");

        // Geçenler / kalanlar
        var passing = students.Where(s => s.Grade >= 60).ToList();
        var failing = students.Where(s => s.Grade < 60).ToList();

        Console.WriteLine($"\nGecen ogrenci sayisi: {passing.Count}");
        Console.WriteLine($"Kalan ogrenci sayisi: {failing.Count}");

        // Sıralama (en yüksekten en düşüğe)
        Console.WriteLine("\nNot siralamasi (yuksekten alcaga):");
        foreach (var s in students.OrderByDescending(s => s.Grade))
        {
            Console.WriteLine($"{s.Name}: {s.Grade}");
        }

        // Ortalama
        double avg = students.Average(s => s.Grade);
        Console.WriteLine($"\nSinif ortalamasi: {avg:F2}");
    }
}
